#include <vector>
#include <cstdlib>

using namespace std;

long long solve(vector<long long> nums) {
    int n = nums.size();
    if (n == 0) return 0;
    int m = n - 1;
    vector<bool> sieve(m + 1, true);
    sieve[0] = sieve[1] = false;
    for (int i = 2; i * i <= m; ++i) {
        if (sieve[i]) {
            for (int j = i * i; j <= m; j += i) {
                sieve[j] = false;
            }
        }
    }
    long long sumA = 0;
    long long sumB = 0;
    for (int i = 0; i < n; ++i) {
        if (sieve[i]) {
            sumA += nums[i];
        } else {
            sumB += nums[i];
        }
    }
    return abs(sumA - sumB);
}

